-- [후검증] 기대: 0 (book-covers 이관본이 모두 원상복구됨)
SELECT COUNT(*) AS still_migrated
FROM books
WHERE source_platform = 'book_dash' AND is_active = true
  AND cover_url LIKE '%/storage/v1/object/public/book-covers/%';
